CREATE TABLE IF NOT EXISTS control_plane_production_e2e_records (LIKE control_plane_accounts INCLUDING DEFAULTS INCLUDING CONSTRAINTS);
CREATE TABLE IF NOT EXISTS control_plane_archive_jobs (LIKE control_plane_accounts INCLUDING DEFAULTS INCLUDING CONSTRAINTS);
CREATE TABLE IF NOT EXISTS control_plane_archived_compute_allocations (LIKE control_plane_accounts INCLUDING DEFAULTS INCLUDING CONSTRAINTS);
CREATE TABLE IF NOT EXISTS control_plane_archived_storage_volumes (LIKE control_plane_accounts INCLUDING DEFAULTS INCLUDING CONSTRAINTS);
