CREATE TABLE IF NOT EXISTS control_plane_archived_admin_audit_events (LIKE control_plane_accounts INCLUDING DEFAULTS INCLUDING CONSTRAINTS);

CREATE INDEX IF NOT EXISTS control_plane_compute_allocations_account_idx ON control_plane_compute_allocations(account_id);
CREATE INDEX IF NOT EXISTS control_plane_storage_volumes_account_idx ON control_plane_storage_volumes(account_id);
CREATE INDEX IF NOT EXISTS control_plane_workspaces_account_idx ON control_plane_workspaces(account_id);
